"""Embedded and external GUI logo/window-icon assets.

Phase 42 moves the bulky base64 logo constants and icon-loading helpers out of
``legacy.py``. The lookup order and fallbacks are intentionally unchanged: assets
next to the public script win, then cwd/assets, then embedded PNG data.
"""

from __future__ import annotations

import base64
import io
import os
import pathlib
from typing import Any, Tuple

from ..logging_setup import logger

_CYOA_LEGACY_PUBLIC_FILE = os.path.abspath(
    os.path.join(os.path.dirname(__file__), os.pardir, os.pardir, "cyoa_downloader.py")
)

_APP_LOGO_LIGHT_B64 = """"""
_APP_LOGO_DARK_B64 = """"""


def _load_logo_images():
    """Return (light_logo, dark_logo) PIL images, or (None, None) on fallback."""
    try:
        from PIL import Image  # type: ignore
        candidates = [
            pathlib.Path(_CYOA_LEGACY_PUBLIC_FILE).resolve().parent / "assets",
            pathlib.Path(os.getcwd()) / "assets",
        ]
        light_path = dark_path = None
        for asset_dir in candidates:
            lp = asset_dir / "logo-light.png"
            dp = asset_dir / "logo-dark.png"
            if lp.exists() and dp.exists():
                light_path, dark_path = lp, dp
                break
        if light_path and dark_path:
            # Keep the dark-mode mark consistent with the canonical white
            # emblem.  Older external bundles may still contain the blue
            # square logo, which should not override the current branding.
            return (
                Image.open(light_path).convert("RGBA"),
                Image.open(io.BytesIO(base64.b64decode(_APP_LOGO_DARK_B64))).convert("RGBA"),
            )
        return (
            Image.open(io.BytesIO(base64.b64decode(_APP_LOGO_LIGHT_B64))).convert("RGBA"),
            Image.open(io.BytesIO(base64.b64decode(_APP_LOGO_DARK_B64))).convert("RGBA"),
        )
    except Exception as e:
        logger.debug(f"Logo fallback used: {e}")
        return None, None




def _load_window_icon_photo(root=None):
    """Load the canonical white emblem as a Tk window/taskbar icon.

    This is intentionally best-effort: missing assets or older Tk builds should
    never block GUI startup.
    """
    try:
        import tkinter as tk
        # Use a small, opaque-backed version for Windows title bars.  Some
        # Tk/Windows combinations fall back to the process icon when given a
        # large transparent PNG, which is how the old blue mark could return.
        try:
            from PIL import Image  # type: ignore

            logo = Image.open(io.BytesIO(base64.b64decode(_APP_LOGO_DARK_B64))).convert("RGBA")
            bbox = logo.getbbox()
            if bbox:
                logo = logo.crop(bbox)
            logo.thumbnail((26, 26), Image.Resampling.LANCZOS)
            icon = Image.new("RGBA", (32, 32), (10, 13, 19, 255))
            icon.alpha_composite(logo, ((32 - logo.width) // 2, (32 - logo.height) // 2))
            payload = io.BytesIO()
            icon.save(payload, format="PNG")
            return tk.PhotoImage(
                master=root,
                data=base64.b64encode(payload.getvalue()).decode("ascii"),
            )
        except Exception as _embedded_icon_exc:
            logger.debug("Embedded window-icon fallback failed: %s", _embedded_icon_exc)
    except Exception as e:
        logger.debug(f"Window icon fallback used: {e}")
    return None

__all__ = [
    "_APP_LOGO_LIGHT_B64", "_APP_LOGO_DARK_B64",
    "_load_logo_images", "_load_window_icon_photo",
]
